use std::sync::mpsc;
use std::thread;

struct LinkRecord {
    original_url: String,
    short_hash: String,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (tx, rx) = mpsc::channel();

    thread::spawn(move || {
        println!("State Machine Thread Running...");
        for received_command in rx {
            match received_command {
                Command::ProcessLink(record) => {
                    println!("Processing link: {}", record.short_hash);
                    let result = format!("{}:{}", record.short_hash, &record.original_url[..10]);
                    println!("State Updated: {}", result);
                }
                Command::HandleRequest(short_key) => {
                    println!("Handling request for key: {}", short_key);
                    if short_key == "abc123x" {
                        println!("Redirecting to stored URL...");
                    } else {
                        eprintln!("Error: Short link not found.");
                    }
                }
            }
        }
    });

    let cmd_tx = tx.clone();

    cmd_tx.send(Command::ProcessLink(LinkRecord {
        original_url: "https://verylongwebsiteaddress.com/page/123".to_string(),
        short_hash: "abc123x".to_string(),
    })).ok();

    thread::sleep(std::time::Duration::from_millis(50));

    cmd_tx.send(Command::HandleRequest("abc123x".to_string())).ok();

    thread::sleep(std::time::Duration::from_millis(50));

    println!("Main execution finished.");
    Ok(())
}

