use tokio::sync::{mpsc, oneshot};
use std::time::Duration;

struct BlogPost {
    id: u32,
    title: String,
    status: String,
}

async fn state_machine(mut rx: mpsc::Receiver<Result<String, String>>, tx: mpsc::Sender<String>) {
    let mut current_state = "initial".to_string();
    println!("State Machine initialized.");

    while let Some(result) = rx.recv().await {
        match result {
            Ok(new_status) => {
                if new_status != current_state {
                    current_state = new_status.clone();
                    let message = format!("Blog post state updated to: {}", &current_state);
                    println!("[State Change] {}", message);

                    if tx.send(message).await.is_err() {
                        eprintln!("Error sending state change notification.");
                        break;
                    }
                } else {
                    println!("Received redundant status update: {}", new_status);
                }
            }
            Err(e) => {
                eprintln!("State machine received error command: {}", e);
            }
        }
    }
    println!("State Machine shutting down.");
}

async fn handle_request(client_tx: mpsc::Sender<String>, state_machine_sender: mpsc::Sender<Result<String, String>>) {
    let post = BlogPost { id: 101, title: "Rust Blog".to_string(), status: "draft".to_string() };

    tokio::time::sleep(Duration::from_millis(50)).await;
    println!("Handler processing initial state for Post ID {}", post.id);

    let publish_command = Ok("published".to_string());
    if state_machine_sender.send(publish_command).await.is_err() {
        eprintln!("Failed to send update command.");
    }

    tokio::time::sleep(Duration::from_millis(100)).await;
    let unpublish_command = Ok("unpublished".to_string());
    if state_machine_sender.send(unpublish_command).await.is_err() {
        eprintln!("Failed to send update command.");
    }


    tokio::time::sleep(Duration::from_millis(500)).await;
}

#[tokio::main]
async fn main() {
    let (command_tx, command_rx) = mpsc::channel::<Result<String, String>>(32);
    let (observer_tx, mut observer_rx) = mpsc::channel::<String>(32);

    tokio::spawn(state_machine(command_rx, observer_tx.clone()));
    tokio::spawn(handle_request(observer_tx.clone(), command_tx));

    println!("--- Observer listening for state changes ---");
    while let Some(message) = observer_rx.recv().await {
        println!("[Observer Received] State Updated: {}", message);
    }
}

use std::sync::mpsc;
use std::thread;
use std::time::Duration;

struct StateMachine {
    receiver: mpsc::Receiver<String>,
}
impl StateMachine {
    fn new(receiver: mpsc::Receiver<String>) -> Self {
        StateMachine { receiver }
    }

    fn run_loop(&self) {
        println!("State Machine started and waiting for updates.");
        while let Ok(message) = self.receiver.recv() {
            if message == "SHUTDOWN" {
                println!("Received shutdown signal. Exiting state machine.");
                break;
            }
            println!("State Machine processed update: {}", message);
        }
    }
}

fn main() {
    let (sender, receiver) = mpsc::channel::<String>();

    let state_machine = StateMachine::new(receiver);

    let state_machine_handle = thread::spawn(move || {
        state_machine.run_loop();
    });

    thread::sleep(Duration::from_millis(500));
    println!("Main thread: Simulating first database update.");
    sender.send(String::from("User profile updated for ID 123")).unwrap();

    thread::sleep(Duration::from_millis(700));
    println!("Main thread: Simulating second, more complex update.");
    sender.send(String::from("Database connection re-established successfully.")).unwrap();

    thread::sleep(Duration::from_millis(500));
    println!("Main thread: Sending shutdown signal.");
    sender.send(String::from("SHUTDOWN")).unwrap();

    state_machine_handle.join().unwrap();
    println!("Program finished gracefully.");
}

use std::io::{self, BufReader, BufRead};

struct AnomalyDetector {
    window_size: usize,
    data_points: Vec<f64>,
}

impl AnomalyDetector {
    fn new(window_size: usize) -> Self {
        AnomalyDetector {
            window_size,
            data_points: Vec::with_capacity(window_size),
        }
    }

    fn process_value(&mut self, value: f64) -> bool {
        if self.data_points.len() >= self.window_size {
            self.data_points.remove(0);
        }
        self.data_points.push(value);

        let mean = self.data_points.iter().sum::<f64>() / self.data_points.len() as f64;
        let variance = self.data_points.iter()
            .map(|&x| (x - mean).powi(2))
            .sum::<f64>() / self.data_points.len() as f64;
        let std_dev = variance.sqrt();

        if std_dev > 0.0 { 
            let z_score = (value - mean) / std_dev;
            z_score.abs() > 3.0
        } else {
            false
        }
    }
}

fn main() -> io::Result<()> {
    let file_path = "sensor_data.log";
    let mut detector = AnomalyDetector::new(10);

    println!("Starting analysis on {}", file_path);

    let file = std::fs::File::open(file_path)?;
    let reader = BufReader::new(file);

    for line in reader.lines() {
        let line = line?;
        if let Ok(value) = line.trim().parse::<f64>() {
            if detector.process_value(value) {
                println!("ANOMALY DETECTED: Value {} exceeded 3-sigma threshold.", value);
            }
        }
    }

    Ok(())
}

use std::sync::{mpsc, Arc, Mutex};
use std::collections::HashMap;

struct BrokerState {
    subscribers: Mutex<HashMap<String, Vec<mpsc::Sender<String>>>>,
}

impl BrokerState {
    fn new() -> Self {
        BrokerState {
            subscribers: Mutex::new(HashMap::new()),
        }
    }
}

struct MessageBroker {
    state: Arc<Mutex<BrokerState>>,
}

impl MessageBroker {
    fn new() -> Self {
        MessageBroker {
            state: Arc::new(Mutex::new(BrokerState::new()))
        }
    }

    fn subscribe(&self, topic: &str, receiver_tx: mpsc::Sender<String>) -> Result<(), String> {
        let mut state = self.state.lock().unwrap();
        let mut subscribers_guard = state.subscribers.lock().unwrap();
        let entry = subscribers_guard.entry(topic.to_string()).or_default();
        entry.push(receiver_tx);
        Ok(()) 
    }

    fn publish(&self, topic: &str, message: String) {
        println!("n[BROKER] Publishing to topic: {}", topic);
        let state = self.state.lock().unwrap();
        let subscribers_map = state.subscribers.lock().unwrap();
        if let Some(senders) = subscribers_map.get(topic) {
            for tx in senders.iter() {
                let _ = tx.send(message.clone());
            }
        }
    }
}

fn main() {
    let broker = MessageBroker::new();

    let topic_a = "infra.alerts";
    let (tx1, rx1) = mpsc::channel::<String>();
    let (tx2, rx2) = mpsc::channel::<String>();

    broker.subscribe(topic_a, tx1).unwrap();
    broker.subscribe(topic_a, tx2).unwrap();

    std::thread::spawn(move || {
        match rx1.recv() {
            Ok(msg) => {
                println!("[CONSUMER 1] Received and processed alert: {}", msg);
            }
            Err(_) => println!("[CONSUMER 1] Failed to receive message (channel closed)."),
        }
    });

    std::thread::spawn(move || {
        match rx2.recv() {
            Ok(msg) => {
                println!("[CONSUMER 2] Received and processed alert: {}", msg);
            }
            Err(_) => println!("[CONSUMER 2] Failed to receive message (channel closed)."),
        }
    });

    broker.publish(topic_a, "Disk utilization exceeded threshold on node-03".to_string());

    std::thread::sleep(std::time::Duration::from_millis(100));
}
